1	/**
2	 * sessionStorage persistence for the parts of `OnboardingState` that survive
3	 * a reload. Server-derived data (snapshot, completedStages, progressByStage)
4	 * is intentionally excluded — it's refetched from the backend on rehydrate
5	 * so we never serve a stale or contradictory snapshot.
6	 */
7	
8	import type { OnboardingState } from "./types";
9	
10	const STORAGE_KEY = "gaia-onboarding-state-v2";
11	
12	interface PersistedShape {
13	  responses: Record<string, string>;
14	  questionIndex: number;
15	  draftText: string;
16	  draftProfession: string | null;
17	  ackedWritingStyle: boolean;
18	  ackedTodos: boolean;
19	  workflowsConfirmed: boolean;
20	  connectedPlatform: string | null;
21	}
22	
23	function pick(state: OnboardingState): PersistedShape {
24	  return {
25	    responses: state.responses,
26	    questionIndex: state.questionIndex,
27	    draftText: state.draftText,
28	    draftProfession: state.draftProfession,
29	    ackedWritingStyle: state.ackedWritingStyle,
30	    ackedTodos: state.ackedTodos,
31	    workflowsConfirmed: state.workflowsConfirmed,
32	    connectedPlatform: state.connectedPlatform,
33	  };
34	}
35	
36	/** Read the persisted slice from sessionStorage. Returns null on miss/parse-fail. */
37	export function loadPersisted(): Partial<OnboardingState> | null {
38	  if (typeof window === "undefined") return null;
39	  try {
40	    const raw = sessionStorage.getItem(STORAGE_KEY);
41	    if (!raw) return null;
42	    const parsed = JSON.parse(raw) as Partial<PersistedShape>;
43	    return {
44	      responses: parsed.responses ?? {},
45	      questionIndex: parsed.questionIndex ?? 0,
46	      draftText: parsed.draftText ?? "",
47	      draftProfession: parsed.draftProfession ?? null,
48	      ackedWritingStyle: parsed.ackedWritingStyle ?? false,
49	      ackedTodos: parsed.ackedTodos ?? false,
50	      workflowsConfirmed: parsed.workflowsConfirmed ?? false,
51	      connectedPlatform: parsed.connectedPlatform ?? null,
52	    };
53	  } catch {
54	    return null;
55	  }
56	}
57	
58	/** Write the whitelisted slice to sessionStorage. Quota errors are swallowed. */
59	export function savePersisted(state: OnboardingState): void {
60	  if (typeof window === "undefined") return;
61	  try {
62	    sessionStorage.setItem(STORAGE_KEY, JSON.stringify(pick(state)));
63	  } catch {
64	    // sessionStorage full or disabled — non-fatal
65	  }
66	}
67	
68	/** Drop the persisted slice — called on restart so the user gets a clean slate. */
69	export function clearPersisted(): void {
70	  if (typeof window === "undefined") return;
71	  try {
72	    sessionStorage.removeItem(STORAGE_KEY);
73	  } catch {
74	    // ignore
75	  }
76	}
