1	/**
2	 * Linear stage cursor. The flow is a fixed queue of stages; the user
3	 * advances forward only, never sideways. Each stage has two checks:
4	 *
5	 * - `isStageReady` — does the backend have the data for this stage yet?
6	 * - `isStageDone`  — is the user past this stage (either acked, or the
7	 *   backend told us there is nothing to show here)?
8	 *
9	 * `getStage` walks the queue once and returns the first stage that is not
10	 * done. If that stage isn't ready, we render `processing` instead of
11	 * skipping ahead — this is what prevents an out-of-order event from
12	 * teleporting the user to a later stage.
13	 *
14	 * The queue is picked once from `hasGmail`: the no-Gmail branch literally
15	 * has no writing-style reveal, so we don't include it.
16	 */
17	
18	import { FIELD_NAMES, questions } from "../constants";
19	import type { OnboardingStage } from "../types/websocket";
20	import type { OnboardingState, Stage } from "./types";
21	
22	export function hasGmail(s: OnboardingState): boolean {
23	  return s.responses[FIELD_NAMES.GMAIL] === "connected";
24	}
25	
26	/**
27	 * The user skipped Gmail and hasn't yet answered the synthetic focus
28	 * question — the no-Gmail branch needs this hint before it can run.
29	 */
30	export function needsFocus(s: OnboardingState): boolean {
31	  return (
32	    s.responses[FIELD_NAMES.GMAIL] === "skipped" &&
33	    s.responses[FIELD_NAMES.FOCUS] == null
34	  );
35	}
36	
37	/** All required answers (incl. focus when Gmail is skipped) are captured. */
38	export function isResponsesComplete(s: OnboardingState): boolean {
39	  return s.questionIndex >= questions.length && !needsFocus(s);
40	}
41	
42	const GMAIL_QUEUE: readonly Stage[] = [
43	  "revealWriting",
44	  "revealTodos",
45	  "workflows",
46	  "platforms",
47	  "chat",
48	];
49	
50	const NO_GMAIL_QUEUE: readonly Stage[] = [
51	  "revealTodos",
52	  "workflows",
53	  "platforms",
54	  "chat",
55	];
56	
57	/**
58	 * True iff the backend has emitted the payload the stage needs to render.
59	 * Stages with no data dependency (`platforms`) are always ready.
60	 */
61	function isStageReady(s: OnboardingState, stage: Stage): boolean {
62	  const b = s.server;
63	  if (!b) return false;
64	  switch (stage) {
65	    case "revealWriting":
66	      return !!b.writing_style?.style_summary;
67	    case "revealTodos":
68	      return (b.onboarding_todos?.length ?? 0) > 0;
69	    case "workflows":
70	      return (b.suggested_workflows?.length ?? 0) > 0;
71	    case "platforms":
72	      return true;
73	    case "chat":
74	      return !!b.first_message_conversation_id;
75	    default:
76	      return false;
77	  }
78	}
79	
80	/**
81	 * True iff the cursor should move past this stage. Either the user has
82	 * acted on it, or the backend has told us there's nothing here to show
83	 * (the matching `*_ready` event landed without any payload data).
84	 *
85	 * `revealWriting` also waits for `revealTodos` to be ready before being
86	 * marked done — that preserves the "Looking for things I can help with…"
87	 * holding block on the writing-style card after the user clicks "Looks
88	 * good" but before the todos data has arrived.
89	 */
90	function isStageDone(s: OnboardingState, stage: Stage): boolean {
91	  const b = s.server;
92	  switch (stage) {
93	    case "revealWriting": {
94	      if (s.ackedWritingStyle && isStageReady(s, "revealTodos")) return true;
95	      // Backend confirmed there's no style to show (LLM failure).
96	      if (
97	        s.completedStages.has("writing_style_ready") &&
98	        !b?.writing_style?.style_summary
99	      ) {
100	        return true;
101	      }
102	      return false;
103	    }
104	    case "revealTodos": {
105	      if (s.ackedTodos) return true;
106	      // Backend confirmed there are no todos to show.
107	      if (
108	        s.completedStages.has("todos_ready") &&
109	        !b?.onboarding_todos?.length
110	      ) {
111	        return true;
112	      }
113	      return false;
114	    }
115	    case "workflows": {
116	      if (s.workflowsConfirmed) return true;
117	      // Backend confirmed there are no workflows to show.
118	      if (
119	        s.completedStages.has("workflows_ready") &&
120	        !b?.suggested_workflows?.length
121	      ) {
122	        return true;
123	      }
124	      return false;
125	    }
126	    case "platforms":
127	      return s.platformsConfirmed;
128	    case "chat":
129	      return false;
130	    default:
131	      return false;
132	  }
133	}
134	
135	/**
136	 * Resolves the stage the page should render right now. Walks the user's
137	 * linear queue (gmail vs no-gmail), returning the first stage that isn't
138	 * done. If that stage's data isn't ready, returns `processing` so the
139	 * spinner / progress checklist takes over until the event arrives.
140	 */
141	export function getStage(s: OnboardingState): Stage {
142	  if (s.questionIndex < questions.length) return "questions";
143	  if (needsFocus(s)) return "focus";
144	
145	  const queue = hasGmail(s) ? GMAIL_QUEUE : NO_GMAIL_QUEUE;
146	
147	  for (const stage of queue) {
148	    if (isStageDone(s, stage)) continue;
149	    if (isStageReady(s, stage)) return stage;
150	    return "processing";
151	  }
152	
153	  return "chat";
154	}
155	
156	/**
157	 * Live progress message for the deepest still-running pipeline stage, or
158	 * `null` if none have emitted yet. Used by the writing-style reveal's
159	 * holding block while we wait for todos.
160	 */
161	const POST_WRITING_PROGRESS_STAGES: readonly OnboardingStage[] = [
162	  "workflows_creating",
163	  "todos_creating",
164	  "triage_analyzing",
165	];
166	
167	export function getCurrentProgress(s: OnboardingState): string | null {
168	  for (const stage of POST_WRITING_PROGRESS_STAGES) {
169	    const value = s.progressByStage[stage];
170	    if (value) return value;
171	  }
172	  return null;
173	}
174	
175	/** Step index per stage for the top progress bar; total is PROGRESS_TOTAL_STEPS. */
176	const STAGE_PROGRESS: Record<Stage, number> = {
177	  questions: 0,
178	  focus: 3,
179	  processing: 3,
180	  revealWriting: 4,
181	  revealTodos: 5,
182	  workflows: 6,
183	  platforms: 7,
184	  chat: 8,
185	};
186	
187	export const PROGRESS_TOTAL_STEPS = 8;
188	
189	/** Step index (0-based) for the top progress bar. Snaps to 0 during restart. */
190	export function getProgress(s: OnboardingState, stage: Stage): number {
191	  if (s.isRestarting) return 0;
192	  if (stage === "questions") return s.questionIndex;
193	  return STAGE_PROGRESS[stage];
194	}
