const connectWs = () => {
  if (closed || aborted) return;
  try {
    const socket = new WebSocket(getWsUrl());
    ws = socket;

    socket.onopen = () => {
      reconnectAttempts = 0;
      // Arm the one-shot silence fallback only on the first connection
      // attempt; on reconnects we've usually seen events already.
      if (
        !silenceFallbackUsed &&
        !wsReceivedEvent &&
        silenceTimer === null
      ) {
        silenceTimer = setTimeout(
          runSilenceFallback,
          WS_SILENCE_FALLBACK_MS,
        );
      }
    };

    socket.onmessage = (event) => {
      if (aborted || isRestartingRef.current) return;
      wsReceivedEvent = true;
      if (silenceTimer) {
        clearTimeout(silenceTimer);
        silenceTimer = null;
      }
      stopPoll();
      try {
        const message = JSON.parse(event.data) as {
          type: string;
          data: unknown;
        };
        if (message.type !== "onboarding_stage") return;
        const envelope = message.data as StageEnvelope;
        console.debug("[onboarding:ws]", envelope.stage, envelope.payload);
        if (!snapshotResolved) {
          buffer.push(envelope);
          return;
        }
        handleStage(envelope);
      } catch (error) {
        console.error("[onboarding:ws] parse error:", error);
      }
    };

    socket.onclose = () => {
      ws = null;
      if (closed || aborted) return;
      if (reconnectAttempts < MAX_RECONNECT_ATTEMPTS) {
        const delay =
          RECONNECT_BASE_DELAY_MS * 2 ** Math.min(reconnectAttempts, 5);
        reconnectAttempts += 1;
        reconnectTimer = setTimeout(connectWs, delay);
      }
    };

    socket.onerror = () => {
      // onclose handles reconnect
    };
  } catch {
    // constructor failed
  }
};

getPersonalization()
  .then((data) => {
    if (aborted) return;
    dispatchRef.current({ type: "serverSnapshot", data });
    snapshotResolved = true;
    flushBuffer();

